// $json here = output of Embed Query Text (embedding result)
// To get original trigger input (person_id, privacy_context), use the trigger node reference
const triggerInput = $('Execute Workflow Trigger').first().json;
const embeddingResult = $input.first().json;  // output of Embed Query Text
const embedding = embeddingResult.data?.[0]?.embedding || [];

const privacyContext = triggerInput.privacy_context || 'public';

return [{
  json: {
    person_id: triggerInput.person_id,
    embedding_str: '[' + embedding.join(',') + ']',
    privacy_context: privacyContext,
    is_private: privacyContext === 'private'
  }
}];

const rows = $input.all()
  .map(i => i.json)
  .filter(r => r && r.content != null);  // Filter out UNION placeholder (null content)
return [{ json: { rows: rows } }];

const rows = $input.all()
  .map(i => i.json)
  .filter(r => r && r.content != null);  // Filter out UNION placeholder (null content)
return [{ json: { rows: rows } }];

const input = $input.first().json;
const rows = input.rows || [];

if (rows.length === 0) {
  return [{ json: { memory_context: '' } }];
}

// Deduplicate by key_label prefix (text before first ':')
// Rows are already sorted by combined_score DESC, so first occurrence wins
const seen = new Set();
const deduped = rows.filter(r => {
  const key = r.content && r.content.includes(':')
    ? r.content.split(':')[0].trim().toLowerCase()
    : r.content ? r.content.trim().toLowerCase() : '';
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Cap at 5 unique memories after dedup
const top = deduped.slice(0, 5);

// Format as bullet list for LLM attention
// Strip key_label prefix from display for natural reading
const lines = top.map((r) => {
  let display = r.content || '';
  if (display.includes(':')) {
    display = display.split(':').slice(1).join(':').trim();
  }
  const age = r.created_at
    ? `(${Math.round((Date.now() - new Date(r.created_at)) / 86400000)}d ago)`
    : '';
  const src = r.source_platform ? `[${r.source_platform}]` : '';
  return `* ${display} ${src} ${age}`.trim();
});

return [{ json: { memory_context: lines.join('\n') } }];

